  ('social-worker-moex-04999', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於聯合國在1979年通過消除對婦女一切形式歧視公約（CEDAW），並在1981年正式生效， 下列敘述何者錯誤？', '["此公約被稱為婦女人權法典", "我國是在2007年經總統批准並頒發加入書", "為明定CEDAW具有國內法效力，我國在2010年經行政院送出消除對婦女一切形式歧視公約 施行法草案，經立法院2011年三讀通過，並自2012年1月1日起施行", "依CEDAW規定，每5年提出我國消除對婦女歧視國家報告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "d372d5f63847", "answer_pdf_sha1": "91733f1aa0c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
